// Extrai items do order_data (JSON string que vem do webhook upstream)
const orderData = $('Extract WhatsApp Data1').first().json.order_data;
let items = [];
try {
  const parsed = typeof orderData === 'string' ? JSON.parse(orderData) : orderData;
  // estrutura comum WhatsApp: { product_items: [ {product_retailer_id, quantity, item_price} ] }
  items = (parsed.product_items || []).map(it => ({
    product_id: String(it.product_retailer_id),
    quantity: Number(it.quantity),
    unit_price: Number(it.item_price)
  }));
} catch(e) {
  items = [];
}
return [{ json: { items_raw: items } }];

const itemsRaw = $('Parse Order Items').first().json.items_raw || [];
const catalogResp = $('Get Items (Catalog)').first().json.items || [];

const catalogMap = {};
for (const c of catalogResp) catalogMap[c.product_id] = c;

const items = itemsRaw.map(r => {
  const c = catalogMap[r.product_id];
  return {
    product_id: r.product_id,
    product_name: c ? c.name : r.product_id,
    quantity: r.quantity,
    unit_price: r.unit_price
  };
});

let subtotal = 0;
for (const i of items) subtotal += i.quantity * i.unit_price;

const ctx = {
  items, subtotal, delivery_fee: 8,
  observation: '', cutlery: null, street: '', district: '', zip: '',
  delivery_address: '', payment_method: '', change_for: 0,
  previous_state: 'rest_catalog_pending'
};

return [{ json: { contexto: ctx } }];

