const client = $('Get Client').first().json;
const ctx = $('Save Cutlery').first().json.contexto || {};
ctx.street = client.street || '';
ctx.district = client.district || '';
ctx.zip = client.zip || '';
ctx.delivery_address = [ctx.street, ctx.district, ctx.zip ? 'CEP ' + ctx.zip : ''].filter(Boolean).join(' - ');
return [{ json: { contexto: ctx } }];

// Build Summary — prioriza ctx mais recente (Parse Address > Inject > Normalize)
let ctx = null;

// 1) Tenta Parse Address (caminho: cliente acabou de digitar endereço novo)
try {
  const pa = $('Parse Address').first().json;
  if (pa && pa.contexto && pa.contexto.items && pa.contexto.items.length > 0) {
    ctx = pa.contexto;
  }
} catch(e) {}

// 2) Tenta Inject Address to Ctx (caminho: cliente já tinha endereço cadastrado)
if (!ctx) {
  try {
    const ia = $('Inject Address to Ctx').first().json;
    if (ia && ia.contexto && ia.contexto.items && ia.contexto.items.length > 0) {
      ctx = ia.contexto;
    }
  } catch(e) {}
}

// 3) Fallback: Normalize State (caminho: cliente clicou Confirmar no resumo já existente)
if (!ctx) {
  try { ctx = $('Normalize State').first().json.contexto; } catch(e) {}
}

if (!ctx) ctx = {};

const fmt = (v) => Number(v || 0).toFixed(2).replace('.', ',');
const itemsTxt = (ctx.items || []).map(i =>
  `• ${i.quantity}x ${i.product_name} — R$ ${fmt(i.quantity * i.unit_price)}`
).join('\n');

const total = (Number(ctx.subtotal) || 0) + (Number(ctx.delivery_fee) || 0);
const obsTxt = ctx.observation ? `\n📝 *Obs:* ${ctx.observation}` : '';
