return [{ json: { whatsapp_body: {
  messaging_product: "whatsapp",
  recipient_type: "individual",
  to: $('Extract WhatsApp Data1').first().json.msg_to,
  type: "interactive",
  interactive: {
    type: "button",
    body: { text },
    action: {
      buttons: [
        { type: "reply", reply: { id: "sum_confirm", title: "✅ Confirmar" } },
        { type: "reply", reply: { id: "sum_change_addr", title: "📍 Alterar endereço" } }
