const text = $('Extract WhatsApp Data1').first().json.msg_text || '';
const ctx = $('Normalize State').first().json.contexto || {};

// Validação mínima: 10 chars
if (String(text).trim().length < 10) {
  return [{ json: { valid: false, reason: 'short' } }];
}

// Parse: tenta extrair CEP (8 dígitos com ou sem hífen)
const cepMatch = text.match(/(\d{5})-?(\d{3})/);
const zip = cepMatch ? `${cepMatch[1]}${cepMatch[2]}` : '';

// Limpa CEP do texto
let rest = text.replace(cepMatch ? cepMatch[0] : '', '').trim();

// Tenta separar por hífen ou último " - " 
let street = rest, district = '';
const parts = rest.split(/\s+-\s+/);
if (parts.length >= 2) {
  street = parts[0].trim();
  district = parts.slice(1).join(' - ').trim();
}

// Limpar pontuação trailing
street = street.replace(/[\s,;-]+$/, '');
district = district.replace(/[\s,;-]+$/, '');

const delivery_address = `${street}${district ? ' - ' + district : ''}${zip ? ' - CEP ' + zip : ''}`;

ctx.street = street;
ctx.district = district;
ctx.zip = zip;
ctx.delivery_address = delivery_address;
ctx.previous_state = 'rest_ask_address';

return [{ json: { valid: true, contexto: ctx } }];

