const data = $('Get History (Pending)').first().json;
const allOrders = data.orders || [];

// Filtrar só pedidos ativos
const ACTIVE = ['pending_payment', 'preparing', 'ready_for_pickup', 'on_delivery', 'Order Placed'];
const orders = allOrders.filter(o => ACTIVE.includes(o.status));

const fmt = (v) => Number(v).toFixed(2).replace('.', ',');

const statusLabel = {
  'pending_payment': '⏳ Aguardando confirmação',
  'preparing': '👨‍🍳 Em preparo',
  'ready_for_pickup': '📦 Pronto para retirada',
  'on_delivery': '🛵 Saiu para entrega',
  'Order Placed': '⏳ Aguardando confirmação'
};

let text;
if (orders.length === 0) {
  text = '📋 Você não tem pedidos em andamento no momento.\n\nEnvie qualquer mensagem para fazer um novo pedido!';
} else {
  const blocks = orders.map((o, i) => {
    const itemsTxt = o.items.map(it => `  • ${it.quantity}x ${it.product_name} — R$ ${fmt(it.line_total)}`).join('\n');
    const label = statusLabel[o.status] || o.status;
    return `*Pedido ${i+1}* — ${o.order_id}\n📅 ${o.created_at}\n${label}\n${itemsTxt}\n💰 Total: R$ ${fmt(o.total)}`;
  });
  text = `📋 *Seus pedidos em andamento:*\n\n${blocks.join('\n\n─────\n\n')}\n\n👋 Atendimento encerrado.\nEnvie qualquer mensagem para um novo atendimento.`;
}

return [{ json: { whatsapp_body: {
  messaging_product: "whatsapp",
  to: $('Extract WhatsApp Data1').first().json.msg_to,
  type: "text",
  text: { body: text }
}}}];

